<?php
namespace Tests\Feature\Admin\Content;use App\Models\CharacterClass;use App\Models\Item;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class EquipmentRequirementsAdminTest extends TestCase{use RefreshDatabase;private $admin;protected function setUp():void{parent::setUp();config(['game_admin.emails'=>['requirements-admin@example.test']]);$this->admin=User::factory()->create(['email'=>'requirements-admin@example.test']);}private function payload($overrides=[]){return array_merge(['code'=>'requirements_admin_item','name'=>'Admin requirement item','description'=>null,'item_type'=>'equipment','equipment_type'=>'weapon','required_level'=>5,'character_class_ids'=>[],'rarity'=>'common','is_stackable'=>0,'max_stack'=>1,'status'=>'active','max_health_bonus'=>0,'attack_bonus'=>1,'defense_bonus'=>0,'accuracy_bonus'=>0,'evasion_bonus'=>0,'critical_chance_bonus'=>0,'attack_speed_bonus'=>0],$overrides);}
public function test_admin_creates_edits_and_removes_requirements_transactionally(){$warrior=CharacterClass::factory()->create(['code'=>'warrior']);$mage=CharacterClass::factory()->create(['code'=>'mage']);$this->actingAs($this->admin)->post(route('admin.content.items.store'),$this->payload(['character_class_ids'=>[$warrior->id,$mage->id]]))->assertRedirect();$item=Item::where('code','requirements_admin_item')->firstOrFail();$this->assertSame(5,$item->required_level);$this->assertEqualsCanonicalizing([$warrior->id,$mage->id],$item->allowedCharacterClasses()->pluck('character_classes.id')->all());$this->put(route('admin.content.items.update',$item),$this->payload(['required_level'=>3,'character_class_ids'=>[]]))->assertRedirect();$this->assertSame(3,$item->fresh()->required_level);$this->assertSame(0,$item->allowedCharacterClasses()->count());}
public function test_inactive_historical_class_can_be_kept_or_removed_but_not_newly_added(){$inactive=CharacterClass::factory()->create(['code'=>'retired','status'=>'inactive']);$item=Item::create(['code'=>'historical_class_item','name'=>'Historical','item_type'=>'equipment','equipment_type'=>'weapon','required_level'=>1,'rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'status'=>'active']);$item->allowedCharacterClasses()->attach($inactive->id);$this->actingAs($this->admin)->get(route('admin.content.items.edit',$item))->assertOk()->assertSee('retired')->assertSee('inactive');$this->put(route('admin.content.items.update',$item),$this->payload(['code'=>$item->code,'character_class_ids'=>[$inactive->id]]))->assertRedirect();$new=$this->payload(['code'=>'new_inactive_relation','character_class_ids'=>[$inactive->id]]);$this->post(route('admin.content.items.store'),$new)->assertSessionHasErrors('content');$this->assertDatabaseMissing('items',['code'=>'new_inactive_relation']);}
public function test_non_equipment_rejects_requirements_and_normal_conversion_clears_pivot(){$class=CharacterClass::factory()->create(['code'=>'warrior']);$this->actingAs($this->admin)->post(route('admin.content.items.store'),$this->payload(['item_type'=>'material','equipment_type'=>null,'is_stackable'=>1,'max_stack'=>10,'required_level'=>2,'character_class_ids'=>[$class->id],'attack_bonus'=>0]))->assertSessionHasErrors('content');$item=Item::create(['code'=>'convert_requirement','name'=>'Convert','item_type'=>'equipment','equipment_type'=>'weapon','required_level'=>2,'rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'status'=>'active']);$item->allowedCharacterClasses()->attach($class->id);$this->put(route('admin.content.items.update',$item),$this->payload(['code'=>$item->code,'item_type'=>'material','equipment_type'=>null,'is_stackable'=>1,'max_stack'=>10,'required_level'=>1,'character_class_ids'=>[],'attack_bonus'=>0]))->assertRedirect();$this->assertSame(1,$item->fresh()->required_level);$this->assertSame(0,$item->allowedCharacterClasses()->count());}
}
